import EditorLayout from "./EditorLayout";

export default function VideoEditor() {
	return <EditorLayout />;
}

import Toolbar from "./Toolbar";
import LeftPanel from "./LeftPanel";
import CanvasPreview from "./CanvasPreview";
import PropertyPanel from "./PropertyPanel";
import Timeline from "./Timeline";
import PreviewControls from "./PreviewControls";
import { StageRefProvider } from "./StageRefContext";
import AudioPlaybackSync from "./AudioPlaybackSync";

export default function EditorLayout() {
	return (
		<StageRefProvider>
			<AudioPlaybackSync />
			<div className="flex flex-col h-dvh overflow-hidden bg-background text-foreground">
				<Toolbar />
				<div className="flex flex-1 min-h-0">
					<LeftPanel />
					<main className="flex-1 flex flex-col min-w-0 min-h-0">
						<CanvasPreview />
						<PreviewControls />
					</main>
					<PropertyPanel />
				</div>
				<Timeline />
			</div>
		</StageRefProvider>
	);
}

import {
	Trash2,
	Copy,
	Undo2,
	Clapperboard,
	Loader2,
	Download,
} from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { useAppDispatch, useAppSelector } from "@/lib/store/hooks";
import {
	setProjectName,
	deleteLayer,
	duplicateLayer,
	resetProject,
	setCurrentTime,
	setPlaying,
	setRendering,
	setAudioUnlocked,
	stopPlayback,
	setCanvasDimensions,
} from "@/lib/store/slices/videoEditorSlice";
import { renderProjectToWebm, downloadBlob } from "@/lib/video-editor/render";
import { useStageRef } from "./StageRefContext";
import FrameDimensionSelect from "./FrameDimensionSelect";

export default function Toolbar() {
	const dispatch = useAppDispatch();
	const stageRef = useStageRef();
	const { project, activeSceneId, selectedLayerId, playback } = useAppSelector(
		(s) => s.videoEditor,
	);

	const handleExport = async () => {
		if (!stageRef?.current) {
			alert("Canvas not ready — wait for preview to load.");
			return;
		}
		dispatch(stopPlayback());
		dispatch(setAudioUnlocked(true));
		dispatch(setRendering(true));
		try {
			const blob = await renderProjectToWebm(
				stageRef,
				project,
				(globalTime, sceneId, localTime) =>
					dispatch(setCurrentTime({ globalTime, sceneId, localTime })),
				(playing) => dispatch(setPlaying(playing)),
			);
			downloadBlob(blob, `${project.name || "video"}.webm`);
		} catch (err) {
			alert(err?.message || "Export failed.");
		} finally {
			dispatch(setRendering(false));
			dispatch(setPlaying(false));
		}
	};

	return (
		<header className="h-12 shrink-0 border-b-2 border-border bg-card flex items-center gap-2 px-3">
			<div className="flex items-center gap-2 shrink-0 mr-2">
				<Clapperboard className="h-5 w-5 text-primary shrink-0" />
				<span className="text-[10px] font-bold uppercase tracking-widest text-primary border-2 border-primary px-1.5 py-0.5 hidden sm:inline">
					Video Editor
				</span>
			</div>

			<Input
				value={project.name}
				onChange={(e) => dispatch(setProjectName(e.target.value))}
				className="h-8 max-w-[160px] sm:max-w-[200px] text-sm font-semibold border-transparent shadow-none focus-visible:border-border"
			/>
			<FrameDimensionSelect
				canvas={project.canvas}
				disabled={playback.isPlaying || playback.isRendering}
				onChange={(dims) => dispatch(setCanvasDimensions(dims))}
			/>

			<div className="flex-1" />

			<Button variant="ghost" size="sm" disabled title="Undo (coming soon)">
				<Undo2 className="h-4 w-4" />
			</Button>

			<Button
				variant="outline"
				size="sm"
				disabled={!selectedLayerId}
				onClick={() =>
					selectedLayerId &&
					dispatch(
						duplicateLayer({ sceneId: activeSceneId, layerId: selectedLayerId }),
					)
				}
			>
				<Copy className="h-4 w-4" />
				<span className="hidden sm:inline">Duplicate</span>
			</Button>

			<Button
				variant="outline"
				size="sm"
				disabled={!selectedLayerId}
				className="text-destructive hover:text-destructive"
				onClick={() =>
					selectedLayerId &&
					dispatch(
						deleteLayer({ sceneId: activeSceneId, layerId: selectedLayerId }),
					)
				}
			>
				<Trash2 className="h-4 w-4" />
				<span className="hidden sm:inline">Delete</span>
			</Button>

			<Button
				size="sm"
				disabled={playback.isRendering || playback.isPlaying}
				onClick={handleExport}
				title="Export video as WebM"
			>
				{playback.isRendering ? (
					<Loader2 className="h-4 w-4 animate-spin" />
				) : (
					<Download className="h-4 w-4" />
				)}
				<span className="hidden sm:inline">
					{playback.isRendering ? "Exporting…" : "Export"}
				</span>
			</Button>

			<Button
				variant="ghost"
				size="sm"
				className="text-muted-foreground"
				onClick={() => {
					if (confirm("Reset project? Unsaved changes will be lost.")) {
						dispatch(resetProject());
					}
				}}
			>
				Reset
			</Button>
		</header>
	);
}

import { useState } from "react";
import {
	Type,
	Image as ImageIcon,
	Video,
	Music,
	Square,
	Star,
	Search,
	Sparkles,
} from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { useAppDispatch, useAppSelector } from "@/lib/store/hooks";
import { addLayer } from "@/lib/store/slices/videoEditorSlice";
import { EDITOR_ICONS } from "@/lib/video-editor/icons";
import { TEXT_PRESETS } from "@/lib/video-editor/textPresets";
import { SHAPE_PRESETS, ICON_COLOR_PRESETS } from "@/lib/video-editor/shapePresets";
import { CANVAS_WIDTH, CANVAS_HEIGHT } from "@/lib/video-editor/constants";
import { getMediaDuration, roundMediaDuration } from "@/lib/video-editor/media";
import { cn } from "@/lib/utils";

const TABS = [
	{ id: "text", label: "Text", icon: Type },
	{ id: "image", label: "Image", icon: ImageIcon },
	{ id: "video", label: "Video", icon: Video, upload: true },
	{ id: "audio", label: "Audio", icon: Music, upload: true },
	{ id: "shape", label: "Objects", icon: Square },
	{ id: "icon", label: "Icons", icon: Star },
];

function openFilePicker(accept, onFile) {
	const input = document.createElement("input");
	input.type = "file";
	input.accept = accept;
	input.onchange = (e) => {
		const file = e.target.files?.[0];
		if (file) onFile(file);
	};
	input.click();
}

function TextPanel({ onAddText, search }) {
	const filtered = TEXT_PRESETS.filter(
		(p) =>
			!search ||
			p.label.toLowerCase().includes(search.toLowerCase()) ||
			p.layer.content.toLowerCase().includes(search.toLowerCase()),
	);
	const plain = filtered.find((p) => p.isPlain);
	const combos = filtered.filter((p) => !p.isPlain);

	return (
		<div className="flex flex-col gap-3 p-3">
			{plain && (
				<Button className="w-full justify-start gap-2 h-10" onClick={() => onAddText(plain)}>
					<Type className="h-4 w-4" />
					Add a text box
				</Button>
			)}
			<Button variant="outline" className="w-full justify-start gap-2 h-10" disabled>
				<Sparkles className="h-4 w-4" />
				Magic Write
			</Button>

			{combos.length > 0 && (
				<>
					<p className="text-sm font-bold text-foreground">Font combinations</p>
					<div className="grid grid-cols-2 gap-2">
						{combos.map((preset) => (
							<button
								key={preset.id}
								type="button"
								onClick={() => onAddText(preset)}
								className="aspect-square border-2 border-border rounded-lg bg-muted/30 hover:border-primary hover:bg-primary/5 transition-colors flex flex-col items-center justify-center p-2 gap-0.5 overflow-hidden"
							>
								{preset.subPreview ? (
									<>
										<span
											className="text-center leading-tight truncate w-full"
											style={preset.preview}
										>
											{preset.label.split("\n")[0]}
										</span>
										<span
											className="text-center leading-tight truncate w-full"
											style={preset.subPreview}
										>
											{preset.subContent}
										</span>
									</>
								) : (
									<span
										className="text-center leading-tight line-clamp-3 w-full"
										style={preset.preview}
									>
										{preset.label}
									</span>
								)}
							</button>
						))}
					</div>
				</>
			)}
		</div>
	);
}

function ImagePanel({ onUpload }) {
	return (
		<div className="flex flex-col gap-3 p-3">
			<p className="text-sm font-bold text-foreground">Images</p>
			<Button variant="outline" className="w-full h-24 flex-col gap-2" onClick={onUpload}>
				<ImageIcon className="h-6 w-6 text-muted-foreground" />
				<span className="text-xs">Upload image</span>
			</Button>
			<p className="text-[10px] text-muted-foreground leading-relaxed">
				Upload PNG, JPG, or WebP. The image is added as a layer on the canvas.
			</p>
		</div>
	);
}

function ShapesPanel({ onAddShape }) {
	return (
		<div className="flex flex-col gap-3 p-3">
			<p className="text-sm font-bold text-foreground">Objects</p>
			<div className="grid grid-cols-2 gap-2">
				{SHAPE_PRESETS.map((preset) => (
					<button
						key={preset.id}
						type="button"
						onClick={() => onAddShape(preset)}
						className="aspect-square border-2 border-border rounded-lg bg-muted/20 hover:border-primary hover:bg-primary/5 transition-colors flex flex-col items-center justify-center gap-2 p-3"
					>
						<div
							className="w-12 h-10 shrink-0"
							style={{
								background: preset.preview.bg,
								borderRadius: preset.preview.borderRadius,
								border: preset.preview.border,
							}}
						/>
						<span className="text-[10px] font-medium text-muted-foreground capitalize">
							{preset.shape}
						</span>
					</button>
				))}
			</div>
		</div>
	);
}

function IconsPanel({ onAddIcon, search }) {
	const [color, setColor] = useState(ICON_COLOR_PRESETS[0]);
	const filtered = EDITOR_ICONS.filter((icon) => !search || icon.includes(search));

	return (
		<div className="flex flex-col gap-3 p-3">
			<p className="text-sm font-bold text-foreground">Icons</p>
			<div className="flex flex-wrap gap-1.5">
				{ICON_COLOR_PRESETS.map((c) => (
					<button
						key={c}
						type="button"
						onClick={() => setColor(c)}
						className={cn(
							"h-6 w-6 rounded-full border-2 shrink-0 transition-transform",
							color === c ? "border-primary scale-110" : "border-border",
						)}
						style={{ background: c }}
						title={c}
					/>
				))}
			</div>
			<div className="grid grid-cols-6 gap-1">
				{filtered.map((icon) => (
					<button
						key={icon}
						type="button"
						onClick={() => onAddIcon(icon, color)}
						className="h-9 w-9 flex items-center justify-center text-xl border-2 border-border rounded-md hover:border-primary hover:bg-primary/5 transition-colors"
						style={{ color }}
						title={`Add ${icon}`}
					>
						{icon}
					</button>
				))}
			</div>
		</div>
	);
}

export default function LeftPanel() {
	const dispatch = useAppDispatch();
	const { activeSceneId, project } = useAppSelector((s) => s.videoEditor);
	const canvasW = project.canvas?.width ?? CANVAS_WIDTH;
	const canvasH = project.canvas?.height ?? CANVAS_HEIGHT;
	const [activeTab, setActiveTab] = useState("text");
	const [search, setSearch] = useState("");

	const addText = (preset) => {
		if (!activeSceneId) return;
		dispatch(
			addLayer({
				sceneId: activeSceneId,
				type: "text",
				data: preset.layer,
				overrides: {
					y: CANVAS_HEIGHT / 2 - 50,
					width: CANVAS_WIDTH - 60,
					height: preset.layer.content.includes("\n") ? 100 : 80,
				},
			}),
		);
	};

	const addShape = (preset) => {
		if (!activeSceneId) return;
		dispatch(
			addLayer({
				sceneId: activeSceneId,
				type: "shape",
				data: preset.data,
				overrides: {
					x: (CANVAS_WIDTH - preset.size.width) / 2,
					y: (CANVAS_HEIGHT - preset.size.height) / 2,
					width: preset.size.width,
					height: preset.size.height,
				},
			}),
		);
	};

	const addIcon = (icon, fill) => {
		if (!activeSceneId) return;
		dispatch(
			addLayer({
				sceneId: activeSceneId,
				type: "icon",
				data: { icon, fill, fontSize: 48 },
				overrides: {
					x: CANVAS_WIDTH / 2 - 30,
					y: CANVAS_HEIGHT / 2 - 30,
				},
			}),
		);
	};

	const uploadImage = () => {
		openFilePicker("image/*", (file) => {
			if (!activeSceneId) return;
			const url = URL.createObjectURL(file);
			dispatch(addLayer({ sceneId: activeSceneId, type: "image", data: { src: url } }));
		});
	};

	const uploadVideo = () => {
		openFilePicker("video/*", async (file) => {
			if (!activeSceneId) return;
			const url = URL.createObjectURL(file);
			try {
				const rawDuration = await getMediaDuration(url, "video");
				const mediaDuration = roundMediaDuration(rawDuration);
				dispatch(
					addLayer({
						sceneId: activeSceneId,
						type: "video",
						mediaDuration,
						data: {
							src: url,
							label: file.name,
							mediaDuration,
							muted: false,
							volume: 1,
						},
						overrides: {
							x: 0,
							y: 0,
							width: canvasW,
							height: canvasH,
						},
					}),
				);
			} catch {
				dispatch(
					addLayer({
						sceneId: activeSceneId,
						type: "video",
						data: { src: url, label: file.name, muted: false, volume: 1 },
						overrides: { x: 0, y: 0, width: canvasW, height: canvasH },
					}),
				);
			}
		});
	};

	const uploadAudio = () => {
		openFilePicker("audio/*", async (file) => {
			if (!activeSceneId) return;
			const url = URL.createObjectURL(file);
			try {
				const rawDuration = await getMediaDuration(url, "audio");
				const mediaDuration = roundMediaDuration(rawDuration);
				dispatch(
					addLayer({
						sceneId: activeSceneId,
						type: "audio",
						mediaDuration,
						data: { src: url, label: file.name, mediaDuration },
					}),
				);
			} catch {
				dispatch(
					addLayer({
						sceneId: activeSceneId,
						type: "audio",
						data: { src: url, label: file.name },
					}),
				);
			}
		});
	};

	const handleTabClick = (tab) => {
		if (tab.upload) {
			if (tab.id === "video") uploadVideo();
			if (tab.id === "audio") uploadAudio();
			return;
		}
		setActiveTab(tab.id);
		setSearch("");
	};

	const showSearch = activeTab === "text" || activeTab === "icon";

	return (
		<aside className="flex shrink-0 border-r-2 border-border bg-card">
			{/* Icon rail */}
			<nav className="w-14 shrink-0 flex flex-col items-center py-2 gap-0.5 border-r-2 border-border bg-muted/20">
				{TABS.map((tab) => {
					const Icon = tab.icon;
					const isActive = !tab.upload && activeTab === tab.id;
					return (
						<button
							key={tab.id}
							type="button"
							onClick={() => handleTabClick(tab)}
							className={cn(
								"w-11 flex flex-col items-center justify-center gap-0.5 py-2 rounded-md text-[9px] font-semibold transition-colors",
								isActive
									? "bg-primary/15 text-primary"
									: "text-muted-foreground hover:bg-muted hover:text-foreground",
							)}
							title={tab.label}
						>
							<Icon className="h-5 w-5" />
							<span className="leading-none">{tab.label}</span>
						</button>
					);
				})}
			</nav>

			{/* Content panel — hidden for video/audio (upload-only) */}
			{activeTab !== "video" && activeTab !== "audio" && (
				<div className="w-56 flex flex-col overflow-hidden">
					{showSearch && (
						<div className="p-2 border-b-2 border-border shrink-0">
							<div className="relative">
								<Search className="absolute left-2.5 top-1/2 -translate-y-1/2 h-3.5 w-3.5 text-muted-foreground" />
								<Input
									value={search}
									onChange={(e) => setSearch(e.target.value)}
									placeholder={
										activeTab === "text"
											? "Search fonts and combinations"
											: "Search icons"
									}
									className="h-8 pl-8 text-xs"
								/>
							</div>
						</div>
					)}

					<div className="flex-1 overflow-y-auto min-h-0">
						{activeTab === "text" && (
							<TextPanel onAddText={addText} search={search} />
						)}
						{activeTab === "image" && <ImagePanel onUpload={uploadImage} />}
						{activeTab === "shape" && <ShapesPanel onAddShape={addShape} />}
						{activeTab === "icon" && (
							<IconsPanel onAddIcon={addIcon} search={search} />
						)}
					</div>
				</div>
			)}

		</aside>
	);
}

import { useRef, useEffect, useState, useCallback, useMemo } from "react";
import { Stage, Layer, Group, Text, Rect, Circle, Ellipse, Image, Transformer } from "react-konva";
import { useAppDispatch, useAppSelector } from "@/lib/store/hooks";
import { selectLayer, updateLayer, duplicateLayerInPlace } from "@/lib/store/slices/videoEditorSlice";
import { CANVAS_WIDTH, CANVAS_HEIGHT } from "@/lib/video-editor/constants";
import { isLayerActiveAtTime } from "@/lib/video-editor/timeline";
import { buildBackgroundFill } from "@/lib/video-editor/gradients";
import {
	computeLayerAnimationState,
	computeSceneTransitionState,
	layerAnimProps,
	shapeAnimProps,
} from "@/lib/video-editor/animations";
import { konvaAltDragHandlers } from "@/lib/video-editor/konvaDrag";
import { useStageRef } from "./StageRefContext";
import CanvasHotkeys from "./CanvasHotkeys";
import KonvaVideoLayer from "./KonvaVideoLayer";
import InlineTextEditor from "./InlineTextEditor";

function useKonvaImage(src) {
	const [image, setImage] = useState(null);
	useEffect(() => {
		if (!src) {
			setImage(null);
			return;
		}
		const img = new window.Image();
		img.crossOrigin = "anonymous";
		img.onload = () => setImage(img);
		img.onerror = () => setImage(null);
		img.src = src;
	}, [src]);
	return image;
}

function KonvaImageLayer({ layer, anim, isSelected, onSelect, onChange, registerRef, interactive, onAltDragDuplicate }) {
	const image = useKonvaImage(layer.data?.src);
	const { data } = layer;
	const altDrag = konvaAltDragHandlers(layer, interactive, onAltDragDuplicate);
	const pos = layerAnimProps(layer, anim);

	return (
		<Image
			ref={registerRef}
			image={image}
			x={pos.x}
			y={pos.y}
			width={layer.width}
			height={layer.height}
			scaleX={pos.scaleX}
			scaleY={pos.scaleY}
			rotation={pos.rotation}
			opacity={pos.opacity}
			visible={layer.visible}
			draggable={interactive && !layer.locked}
			onClick={onSelect}
			onTap={onSelect}
			{...altDrag}
			onDragEnd={(e) =>
				onChange({ x: e.target.x(), y: e.target.y() })
			}
			onTransformEnd={(e) => {
				const node = e.target;
				const scaleX = node.scaleX();
				const scaleY = node.scaleY();
				onChange({
					x: node.x(),
					y: node.y(),
					width: Math.max(20, node.width() * scaleX),
					height: Math.max(20, node.height() * scaleY),
					rotation: node.rotation(),
				});
				node.scaleX(1);
				node.scaleY(1);
			}}
			cornerRadius={data?.borderRadius ?? 0}
			shadowBlur={data?.shadowBlur ?? 0}
			shadowColor={data?.shadowColor ?? "black"}
			stroke={isSelected ? "#ea580c" : undefined}
			strokeWidth={isSelected ? 2 : 0}
		/>
	);
}

function PlaceholderLayer({ layer, anim, isSelected, onSelect, onChange, registerRef, color, label, interactive, onAltDragDuplicate }) {
	const altDrag = konvaAltDragHandlers(layer, interactive, onAltDragDuplicate);
	const pos = layerAnimProps(layer, anim);
	return (
		<>
			<Rect
				ref={registerRef}
				x={pos.x}
				y={pos.y}
				width={layer.width}
				height={layer.height}
				scaleX={pos.scaleX}
				scaleY={pos.scaleY}
				rotation={pos.rotation}
				opacity={pos.opacity}
				visible={layer.visible}
				fill={color}
				cornerRadius={8}
				draggable={interactive && !layer.locked}
				onClick={onSelect}
				onTap={onSelect}
				{...altDrag}
				onDragEnd={(e) =>
					onChange({ x: e.target.x(), y: e.target.y() })
				}
				onTransformEnd={(e) => {
					const node = e.target;
					const scaleX = node.scaleX();
					const scaleY = node.scaleY();
					onChange({
						x: node.x(),
						y: node.y(),
						width: Math.max(20, node.width() * scaleX),
						height: Math.max(20, node.height() * scaleY),
						rotation: node.rotation(),
					});
					node.scaleX(1);
					node.scaleY(1);
				}}
				stroke={isSelected ? "#ea580c" : "#52525b"}
				strokeWidth={isSelected ? 2 : 1}
				dash={[6, 4]}
			/>
			<Text
				x={layer.x}
				y={layer.y + layer.height / 2 - 10}
				width={layer.width}
				text={label}
				fontSize={14}
				fontFamily="DM Sans"
				fill="#ffffff"
				align="center"
				listening={false}
				opacity={layer.opacity}
				visible={layer.visible}
			/>
		</>
	);
}

function LayerNode({
	layer,
	sceneDuration,
	previewTime,
	applyAnimation,
	isPlaying,
	audioUnlocked,
	isSelected,
	onSelect,
	onChange,
	registerRef,
	interactive,
	onAltDragDuplicate,
	onStartEdit,
	isEditing,
}) {
	const { data } = layer;
	const altDrag = konvaAltDragHandlers(layer, interactive, onAltDragDuplicate);
	const anim = applyAnimation
		? computeLayerAnimationState(layer, previewTime)
		: computeLayerAnimationState(layer, Infinity);
	const pos = layerAnimProps(layer, anim);

	if (layer.type === "text") {
		const displayText = isEditing ? data.content : (anim.displayText ?? data.content);
		return (
			<Text
				ref={registerRef}
				x={pos.x}
				y={pos.y}
				width={layer.width}
				text={displayText}
				fontSize={data.fontSize}
				fontFamily={data.fontFamily}
				fontStyle={data.fontWeight >= 600 ? "bold" : "normal"}
				fill={data.fill}
				align={data.align}
				letterSpacing={data.letterSpacing}
				lineHeight={data.lineHeight}
				scaleX={pos.scaleX}
				scaleY={pos.scaleY}
				rotation={pos.rotation}
				opacity={isEditing ? 0 : pos.opacity}
				visible={layer.visible && !isEditing}
				shadowColor={data.shadowColor}
				shadowBlur={data.shadowBlur}
				shadowOffsetX={data.shadowOffsetX}
				shadowOffsetY={data.shadowOffsetY}
				stroke={data.stroke || undefined}
				strokeWidth={data.strokeWidth || 0}
				draggable={interactive && !layer.locked && !isEditing}
				onClick={onSelect}
				onTap={onSelect}
				onDblClick={(e) => {
					e.cancelBubble = true;
					if (interactive && !layer.locked && onStartEdit) onStartEdit();
				}}
				onDblTap={(e) => {
					e.cancelBubble = true;
					if (interactive && !layer.locked && onStartEdit) onStartEdit();
				}}
				{...altDrag}
				onDragEnd={(e) =>
					onChange({ x: e.target.x(), y: e.target.y() })
				}
				onTransformEnd={(e) => {
					const node = e.target;
					const scaleX = node.scaleX();
					const scaleY = node.scaleY();
					onChange({
						x: node.x(),
						y: node.y(),
						width: Math.max(40, node.width() * scaleX),
						height: Math.max(20, node.height() * scaleY),
						rotation: node.rotation(),
					});
					node.scaleX(1);
					node.scaleY(1);
				}}
			/>
		);
	}

	if (layer.type === "image") {
		return (
			<KonvaImageLayer
				layer={layer}
				anim={anim}
				isSelected={isSelected}
				onSelect={onSelect}
				onChange={onChange}
				registerRef={registerRef}
				interactive={interactive}
				onAltDragDuplicate={onAltDragDuplicate}
			/>
		);
	}

	if (layer.type === "video") {
		return (
			<KonvaVideoLayer
				layer={layer}
				anim={anim}
				sceneDuration={sceneDuration}
				previewTime={previewTime}
				isPlaying={isPlaying}
				audioUnlocked={audioUnlocked}
				isSelected={isSelected}
				onSelect={onSelect}
				onChange={onChange}
				registerRef={registerRef}
				interactive={interactive}
				onAltDragDuplicate={onAltDragDuplicate}
			/>
		);
	}

	if (layer.type === "audio") {
		return (
			<PlaceholderLayer
				layer={layer}
				anim={anim}
				isSelected={isSelected}
				onSelect={onSelect}
				onChange={onChange}
				registerRef={registerRef}
				color="rgba(16,185,129,0.35)"
				label={data?.label || "Audio"}
				interactive={interactive}
				onAltDragDuplicate={onAltDragDuplicate}
			/>
		);
	}

	if (layer.type === "icon") {
		return (
			<Text
				ref={registerRef}
				x={pos.x}
				y={pos.y}
				width={layer.width}
				height={layer.height}
				text={data.icon}
				fontSize={data.fontSize ?? 48}
				fill={data.fill}
				align="center"
				verticalAlign="middle"
				scaleX={pos.scaleX}
				scaleY={pos.scaleY}
				rotation={pos.rotation}
				opacity={pos.opacity}
				visible={layer.visible}
				draggable={interactive && !layer.locked}
				onClick={onSelect}
				onTap={onSelect}
				{...altDrag}
				onDragEnd={(e) =>
					onChange({ x: e.target.x(), y: e.target.y() })
				}
				onTransformEnd={(e) => {
					const node = e.target;
					const scaleX = node.scaleX();
					const scaleY = node.scaleY();
					onChange({
						x: node.x(),
						y: node.y(),
						width: Math.max(20, node.width() * scaleX),
						height: Math.max(20, node.height() * scaleY),
						rotation: node.rotation(),
					});
					node.scaleX(1);
					node.scaleY(1);
				}}
			/>
		);
	}

	if (layer.type === "shape") {
		const isCentered = data.shape === "circle" || data.shape === "ellipse";
		const shapePos = shapeAnimProps(layer, anim);
		const shapeDragEnd = (e) => {
			const nx = e.target.x();
			const ny = e.target.y();
			onChange(
				isCentered
					? { x: nx - layer.width / 2, y: ny - layer.height / 2 }
					: { x: nx, y: ny },
			);
		};
		const common = {
			ref: registerRef,
			x: shapePos.x,
			y: shapePos.y,
			scaleX: shapePos.scaleX,
			scaleY: shapePos.scaleY,
			rotation: shapePos.rotation,
			opacity: shapePos.opacity,
			visible: layer.visible,
			fill: data.fill,
			stroke: data.stroke || undefined,
			strokeWidth: data.strokeWidth ?? 0,
			draggable: interactive && !layer.locked,
			onClick: onSelect,
			onTap: onSelect,
			...altDrag,
			onDragEnd: shapeDragEnd,
			onTransformEnd: (e) => {
				const node = e.target;
				const scaleX = node.scaleX();
				const scaleY = node.scaleY();
				onChange({
					x: node.x(),
					y: node.y(),
					width: Math.max(10, node.width() * scaleX),
					height: Math.max(10, node.height() * scaleY),
					rotation: node.rotation(),
				});
				node.scaleX(1);
				node.scaleY(1);
			},
		};

		if (data.shape === "circle") {
			return (
				<Circle
					{...common}
					x={layer.x + layer.width / 2}
					y={layer.y + layer.height / 2}
					radius={Math.min(layer.width, layer.height) / 2}
				/>
			);
		}
		if (data.shape === "ellipse") {
			return (
				<Ellipse
					{...common}
					x={layer.x + layer.width / 2}
					y={layer.y + layer.height / 2}
					radiusX={layer.width / 2}
					radiusY={layer.height / 2}
				/>
			);
		}
		return (
			<Rect
				{...common}
				width={layer.width}
				height={layer.height}
				cornerRadius={data.cornerRadius ?? 0}
			/>
		);
	}

	return null;
}

export default function CanvasPreview() {
	const dispatch = useAppDispatch();
	const { project, activeSceneId, selectedLayerId, playback } = useAppSelector(
		(s) => s.videoEditor,
	);
	const stageRef = useStageRef();
	const containerRef = useRef(null);
	const transformerRef = useRef(null);
	const nodeRefs = useRef({});
	const altDragPendingRef = useRef(false);

	const [scale, setScale] = useState(0.5);
	const [canvasFocused, setCanvasFocused] = useState(false);
	const [editingLayerId, setEditingLayerId] = useState(null);

	const canvasW = project.canvas?.width ?? CANVAS_WIDTH;
	const canvasH = project.canvas?.height ?? CANVAS_HEIGHT;
	const bgFill = buildBackgroundFill(project.canvas?.background, canvasW, canvasH);

	const activeScene = project.scenes.find((s) => s.id === activeSceneId);
	const previewTime = playback.previewLocalTime ?? 0;
	const interactive = !playback.isPlaying && !playback.isRendering;
	const isPlaying = playback.isPlaying || playback.isRendering;
	const applyAnimation = isPlaying;
	const audioUnlocked = playback.audioUnlocked;

	const sceneTransition = useMemo(() => {
		if (!activeScene) {
			return {
				contentOpacity: 1,
				contentScale: 1,
				offsetX: 0,
				offsetY: 0,
				blackOverlay: 0,
				whiteOverlay: 0,
				clipRect: null,
			};
		}
		return computeSceneTransitionState(activeScene, previewTime, canvasW, canvasH);
	}, [activeScene, previewTime, canvasW, canvasH]);

	const layers = useMemo(() => {
		const all = activeScene?.layers ?? [];
		if (!activeScene) return all;
		return all.filter((layer) =>
			isLayerActiveAtTime(layer, activeScene.duration, previewTime),
		);
	}, [activeScene, previewTime]);

	const editingLayer = useMemo(() => {
		if (!editingLayerId || !activeScene) return null;
		const layer = activeScene.layers.find((l) => l.id === editingLayerId);
		return layer?.type === "text" ? layer : null;
	}, [editingLayerId, activeScene]);

	useEffect(() => {
		if (!interactive) setEditingLayerId(null);
	}, [interactive]);

	useEffect(() => {
		setEditingLayerId(null);
	}, [activeSceneId]);

	useEffect(() => {
		if (editingLayerId && selectedLayerId !== editingLayerId) {
			setEditingLayerId(null);
		}
	}, [selectedLayerId, editingLayerId]);

	const recalcScale = useCallback(() => {
		const el = containerRef.current;
		if (!el) return;
		const pad = 48;
		const maxW = el.clientWidth - pad;
		const maxH = el.clientHeight - pad;
		if (maxW <= 0 || maxH <= 0) return;
		const s = Math.min(maxW / canvasW, maxH / canvasH, 1.2);
		setScale(Math.max(0.25, s));
	}, [canvasW, canvasH]);

	useEffect(() => {
		recalcScale();
		const el = containerRef.current;
		if (!el) return;
		const ro = new ResizeObserver(() => recalcScale());
		ro.observe(el);
		window.addEventListener("resize", recalcScale);
		return () => {
			ro.disconnect();
			window.removeEventListener("resize", recalcScale);
		};
	}, [recalcScale]);

	useEffect(() => {
		const tr = transformerRef.current;
		if (!tr) return;
		if (interactive && selectedLayerId && !editingLayerId && nodeRefs.current[selectedLayerId]) {
			tr.nodes([nodeRefs.current[selectedLayerId]]);
		} else {
			tr.nodes([]);
		}
		tr.getLayer()?.batchDraw();
	}, [selectedLayerId, layers, interactive, editingLayerId]);

	const handleStageClick = (e) => {
		if (e.target === e.target.getStage()) {
			setEditingLayerId(null);
			dispatch(selectLayer(null));
		}
	};

	const handleLayerChange = (layerId) => (changes) => {
		dispatch(
			updateLayer({
				sceneId: activeSceneId,
				layerId,
				changes,
			}),
		);
	};

	const handleAltDragDuplicate = useCallback(
		(layerId) => {
			if (!activeSceneId) return;
			dispatch(duplicateLayerInPlace({ sceneId: activeSceneId, layerId }));
			altDragPendingRef.current = true;
		},
		[dispatch, activeSceneId],
	);

	useEffect(() => {
		if (!altDragPendingRef.current || !selectedLayerId) return;
		altDragPendingRef.current = false;
		const id = selectedLayerId;
		requestAnimationFrame(() => {
			nodeRefs.current[id]?.startDrag();
		});
	}, [selectedLayerId, layers]);

	return (
		<div
			ref={containerRef}
			tabIndex={0}
			onFocus={() => setCanvasFocused(true)}
			onBlur={() => setCanvasFocused(false)}
			onMouseDown={() => containerRef.current?.focus()}
			className="flex-1 flex items-center justify-center bg-muted/40 overflow-hidden min-h-0 outline-none focus:ring-2 focus:ring-primary/30 focus:ring-inset"
		>
			<CanvasHotkeys enabled={canvasFocused && interactive && !editingLayerId} />
			<div
				className="border-2 border-border shadow-md shrink-0 relative"
				style={{
					width: canvasW * scale,
					height: canvasH * scale,
				}}
			>
				<Stage
					ref={stageRef}
					width={canvasW * scale}
					height={canvasH * scale}
					scaleX={scale}
					scaleY={scale}
					onMouseDown={interactive ? handleStageClick : undefined}
					onTouchStart={interactive ? handleStageClick : undefined}
				>
					<Layer>
						<Group
							x={canvasW / 2 + sceneTransition.offsetX}
							y={canvasH / 2 + sceneTransition.offsetY}
							offsetX={canvasW / 2}
							offsetY={canvasH / 2}
							scaleX={sceneTransition.contentScale}
							scaleY={sceneTransition.contentScale}
							opacity={sceneTransition.contentOpacity}
							clipFunc={
								sceneTransition.clipRect
									? (ctx) => {
											const r = sceneTransition.clipRect;
											ctx.rect(r.x, r.y, r.width, r.height);
										}
									: undefined
							}
						>
							<Rect x={0} y={0} width={canvasW} height={canvasH} listening={false} {...bgFill} />
							{layers.map((layer) => (
								<LayerNode
									key={layer.id}
									layer={layer}
									sceneDuration={activeScene?.duration ?? 5}
									previewTime={previewTime}
									applyAnimation={applyAnimation}
									isPlaying={isPlaying}
									audioUnlocked={audioUnlocked}
									isSelected={interactive && layer.id === selectedLayerId}
									isEditing={editingLayerId === layer.id}
									onSelect={() => {
										if (!interactive) return;
										dispatch(selectLayer(layer.id));
									}}
									onStartEdit={
										layer.type === "text" && interactive && !layer.locked
											? () => {
													dispatch(selectLayer(layer.id));
													setEditingLayerId(layer.id);
												}
											: undefined
									}
									onChange={handleLayerChange(layer.id)}
									registerRef={(node) => {
										nodeRefs.current[layer.id] = node;
									}}
									interactive={interactive}
									onAltDragDuplicate={handleAltDragDuplicate}
								/>
							))}
							{interactive && (
								<Transformer
									ref={transformerRef}
									rotateEnabled
									enabledAnchors={[
										"top-left",
										"top-right",
										"bottom-left",
										"bottom-right",
										"middle-left",
										"middle-right",
										"top-center",
										"bottom-center",
									]}
									borderStroke="#ea580c"
									anchorStroke="#ea580c"
									anchorFill="#ffffff"
									anchorSize={8}
									borderStrokeWidth={2}
									boundBoxFunc={(oldBox, newBox) => {
										if (newBox.width < 10 || newBox.height < 10) return oldBox;
										return newBox;
									}}
								/>
							)}
						</Group>
						{sceneTransition.blackOverlay > 0 && (
							<Rect
								x={0}
								y={0}
								width={canvasW}
								height={canvasH}
								fill="#000000"
								opacity={sceneTransition.blackOverlay}
								listening={false}
							/>
						)}
						{sceneTransition.whiteOverlay > 0 && (
							<Rect
								x={0}
								y={0}
								width={canvasW}
								height={canvasH}
								fill="#ffffff"
								opacity={sceneTransition.whiteOverlay}
								listening={false}
							/>
						)}
					</Layer>
				</Stage>
				{editingLayer && nodeRefs.current[editingLayer.id] ? (
					<InlineTextEditor
						layer={editingLayer}
						nodeRef={nodeRefs.current[editingLayer.id]}
						stageScale={scale}
						sceneId={activeSceneId}
						onClose={() => setEditingLayerId(null)}
					/>
				) : null}
			</div>
		</div>
	);
}

