export function resolveFramePreset(canvas) {
	if (!canvas) return getFramePresetById(DEFAULT_FRAME_PRESET_ID);

	if (canvas.presetId) {
		const byId = getFramePresetById(canvas.presetId);
		if (byId) return byId;
	}

	const bySize = FRAME_DIMENSION_PRESETS.find(
		(p) => p.width === canvas.width && p.height === canvas.height,
	);
	if (bySize) return bySize;

	const ratio = canvas.width / canvas.height;
	const byRatio = FRAME_DIMENSION_PRESETS.find(
		(p) => Math.abs(p.width / p.height - ratio) < 0.02,
	);
	if (byRatio) return byRatio;

	return {
		id: "custom",
		label: "Custom",
		sublabel: `${canvas.width}×${canvas.height}`,
		width: canvas.width,
		height: canvas.height,
		group: "Custom",
	};
}

export function groupFramePresets() {
	const groups = {};
	for (const preset of FRAME_DIMENSION_PRESETS) {
		if (!groups[preset.group]) groups[preset.group] = [];
		groups[preset.group].push(preset);
	}
	return groups;
}

/** Build Konva linear/radial gradient props for a Rect fill */

export const DEFAULT_CANVAS_BACKGROUND = {
	type: "solid",
	fill: "#18181b",
	gradient: {
		type: "linear",
		angle: 180,
		stops: [
			{ offset: 0, color: "#1a1a2e" },
			{ offset: 0.5, color: "#16213e" },
			{ offset: 1, color: "#0f3460" },
		],
	},
};

function angleToPoints(angleDeg, width, height) {
	const rad = ((angleDeg - 90) * Math.PI) / 180;
	const cx = width / 2;
	const cy = height / 2;
	const len = Math.sqrt(width * width + height * height) / 2;
	return {
		start: { x: cx - Math.cos(rad) * len, y: cy - Math.sin(rad) * len },
		end: { x: cx + Math.cos(rad) * len, y: cy + Math.sin(rad) * len },
	};
}

export function buildBackgroundFill(canvasBg, width, height) {
	if (!canvasBg || canvasBg.type === "solid") {
		return { fill: canvasBg?.fill ?? "#18181b" };
	}

	const { gradient } = canvasBg;
	const stops = gradient?.stops ?? DEFAULT_CANVAS_BACKGROUND.gradient.stops;
	const flatStops = stops.flatMap((s) => [s.offset, s.color]);

	if (gradient?.type === "radial") {
		return {
			fillRadialGradientStartPoint: { x: width / 2, y: height / 2 },
			fillRadialGradientEndPoint: { x: width / 2, y: height / 2 },
			fillRadialGradientStartRadius: 0,
			fillRadialGradientEndRadius: Math.max(width, height) / 2,
			fillRadialGradientColorStops: flatStops,
		};
	}

	const { start, end } = angleToPoints(gradient?.angle ?? 180, width, height);
	return {
		fillLinearGradientStartPoint: start,
		fillLinearGradientEndPoint: end,
		fillLinearGradientColorStops: flatStops,
	};
}

export function gradientCssPreview(canvasBg) {
	if (!canvasBg || canvasBg.type === "solid") {
		return canvasBg?.fill ?? "#18181b";
	}
	const stops = canvasBg.gradient?.stops ?? [];
	const parts = stops.map((s) => `${s.color} ${s.offset * 100}%`).join(", ");
	if (canvasBg.gradient?.type === "radial") {
		return `radial-gradient(circle, ${parts})`;
	}
	const angle = canvasBg.gradient?.angle ?? 180;
	return `linear-gradient(${angle}deg, ${parts})`;
}

/**
 * Position/style helpers for HTML textarea overlay on Konva text nodes.
 */

export function getInlineTextareaStyle(layer, node, stageScale) {
	if (!node || !layer?.data) return null;

	const data = layer.data;
	const scaleX = typeof node.scaleX === "function" ? node.scaleX() : 1;
	const scaleY = typeof node.scaleY === "function" ? node.scaleY() : 1;
	const nodeW = (typeof node.width === "function" ? node.width() : layer.width) * scaleX;
	const nodeH =
		(typeof node.height === "function" ? node.height() : layer.height) * scaleY;

	const fontSize = (data.fontSize ?? 36) * stageScale;
	const lineHeight = data.lineHeight ?? 1.2;

	return {
		position: "absolute",
		left: node.x() * stageScale,
		top: node.y() * stageScale,
		width: Math.max(40, nodeW * stageScale),
		minHeight: Math.max(fontSize * lineHeight * 1.5, nodeH * stageScale),
		fontSize,
		fontFamily: data.fontFamily ?? "DM Sans",
		fontWeight: data.fontWeight ?? 400,
		color: data.fill ?? "#ffffff",
		textAlign: data.align ?? "left",
		letterSpacing: data.letterSpacing ? `${data.letterSpacing}px` : undefined,
		lineHeight,
		transform: layer.rotation ? `rotate(${layer.rotation}deg)` : undefined,
		transformOrigin: "top left",
		zIndex: 30,
	};
}

/** Estimate layer height from wrapped text after edit */
export function estimateTextLayerHeight(content, layer, stageScale = 1) {
	const data = layer.data ?? {};
	const fontSize = data.fontSize ?? 36;
	const lineHeight = data.lineHeight ?? 1.2;
	const width = layer.width || 280;
	const lines = String(content || "").split("\n");
	let totalLines = 0;
	const avgCharWidth = fontSize * 0.55;
	const charsPerLine = Math.max(1, Math.floor(width / avgCharWidth));

	for (const line of lines) {
		if (!line) {
			totalLines += 1;
			continue;
		}
		totalLines += Math.max(1, Math.ceil(line.length / charsPerLine));
	}

	return Math.max(24, Math.ceil(totalLines * fontSize * lineHeight) + 8);
}

/** Konva drag helpers for video editor canvas */

export function getLayerNodePosition(layer) {
	if (layer.type === "shape") {
		const shape = layer.data?.shape;
		if (shape === "circle" || shape === "ellipse") {
			return { x: layer.x + layer.width / 2, y: layer.y + layer.height / 2 };
		}
	}
	return { x: layer.x, y: layer.y };
}

/** Option/Alt + drag → duplicate in place and drag the copy */
export function konvaAltDragHandlers(layer, interactive, onAltDragDuplicate) {
	if (!interactive || !onAltDragDuplicate) return {};
	return {
		onDragStart: (e) => {
			if (!e.evt.altKey) return;
			e.target.stopDrag();
			e.target.position(getLayerNodePosition(layer));
			onAltDragDuplicate(layer.id);
		},
	};
}

/** Probe duration of a video or audio blob/url before adding to timeline */

export function getMediaDuration(src, kind = "video") {
	return new Promise((resolve, reject) => {
		const el = document.createElement(kind === "audio" ? "audio" : "video");
		el.preload = "metadata";
		el.muted = true;

		const cleanup = () => {
			el.removeAttribute("src");
			el.load();
		};

		el.onloadedmetadata = () => {
			const duration = el.duration;
			cleanup();
			if (Number.isFinite(duration) && duration > 0) {
				resolve(duration);
			} else {
				reject(new Error("Could not read media duration"));
			}
		};
		el.onerror = () => {
			cleanup();
			reject(new Error("Failed to load media metadata"));
		};
		el.src = src;
	});
}

export function roundMediaDuration(seconds) {
	return Math.round(seconds * 100) / 100;
}

import { getTotalDuration, resolveTime } from "./timeline";

function sleep(ms) {
	return new Promise((r) => setTimeout(r, ms));
}

function nextFrame() {
	return new Promise((resolve) => {
		requestAnimationFrame(() => requestAnimationFrame(resolve));
	});
}

/**
 * Render project preview to WebM by stepping the Konva stage frame-by-frame.
 */
export async function renderProjectToWebm(stageRef, project, onTimeUpdate, onPlayingChange) {
	const stage = stageRef?.current;
	if (!stage) throw new Error("Canvas not ready");

	const total = getTotalDuration(project.scenes);
	if (total <= 0) throw new Error("Project has no duration");

	const pixelRatio = 2;
	const w = stage.width() * pixelRatio;
	const h = stage.height() * pixelRatio;

	const recordCanvas = document.createElement("canvas");
	recordCanvas.width = w;
	recordCanvas.height = h;
	const ctx = recordCanvas.getContext("2d");

	const stream = recordCanvas.captureStream(30);
	const mimeType = MediaRecorder.isTypeSupported("video/webm;codecs=vp9")
		? "video/webm;codecs=vp9"
		: "video/webm";

	const recorder = new MediaRecorder(stream, {
		mimeType,
		videoBitsPerSecond: 4_000_000,
	});

	const chunks = [];
	recorder.ondataavailable = (e) => {
		if (e.data.size > 0) chunks.push(e.data);
	};

	const done = new Promise((resolve, reject) => {
		recorder.onstop = () => resolve(new Blob(chunks, { type: mimeType }));
		recorder.onerror = reject;
	});

	onPlayingChange(true);
	recorder.start(100);

	const fps = 30;
	const frameMs = 1000 / fps;
	const start = performance.now();

	for (let frame = 0; frame <= Math.ceil(total * fps); frame += 1) {
		const elapsed = frame / fps;
		const t = Math.min(elapsed, total - 0.001);
		const { scene, localTime } = resolveTime(project.scenes, t);

		onTimeUpdate(t, scene?.id, localTime);
		await nextFrame();

		stage.batchDraw();
		const frameCanvas = stage.toCanvas({ pixelRatio });
		ctx.clearRect(0, 0, w, h);
		ctx.drawImage(frameCanvas, 0, 0, w, h);

		const track = stream.getVideoTracks()[0];
		if (track?.requestFrame) track.requestFrame();

		const target = start + frame * frameMs;
		const wait = target - performance.now();
		if (wait > 0) await sleep(wait);
	}

	onTimeUpdate(0, project.scenes[0]?.id, 0);
	onPlayingChange(false);
	stage.batchDraw();
	recorder.stop();

	return done;
}

export function downloadBlob(blob, filename) {
	const url = URL.createObjectURL(blob);
	const a = document.createElement("a");
	a.href = url;
	a.download = filename;
	a.click();
	URL.revokeObjectURL(url);
}

import {
	DEFAULT_SCENE_TRANSITION,
	DEFAULT_SCENE_ENTER_ANIMATION,
} from "./animations";

/** Pixels per second on the timeline ruler */
export const PX_PER_SEC = 72;
export const MIN_SCENE_DURATION = 0.5;
export const MIN_CLIP_DURATION = 0.25;
export const TIMELINE_TRACK_HEIGHT = 36;

/** Track display order (top → bottom) */
export const TRACK_ORDER = ["video", "image", "text", "shape", "icon", "audio"];

export const TRACK_META = {
	video: { label: "Video", color: "bg-blue-500", border: "border-blue-600", text: "text-blue-950" },
	image: { label: "Image", color: "bg-amber-400", border: "border-amber-500", text: "text-amber-950" },
	text: { label: "Text", color: "bg-violet-500", border: "border-violet-600", text: "text-white" },
	shape: { label: "Shape", color: "bg-orange-500", border: "border-orange-600", text: "text-white" },
	icon: { label: "Icon", color: "bg-pink-500", border: "border-pink-600", text: "text-white" },
	audio: { label: "Audio", color: "bg-emerald-500", border: "border-emerald-600", text: "text-emerald-950" },
};

export function getTotalDuration(scenes) {
	return scenes.reduce((sum, s) => sum + (s.duration || 0), 0);
}

export function getLayerClipDuration(layer, sceneDuration) {
	const d = layer.clipDuration ?? sceneDuration;
	return Math.max(MIN_CLIP_DURATION, Math.min(d, sceneDuration - (layer.startTime || 0)));
}

export function isLayerActiveAtTime(layer, sceneDuration, localTime) {
	if (!layer.visible) return false;
	const start = layer.startTime || 0;
	const end = start + getLayerClipDuration(layer, sceneDuration);
	return localTime >= start && localTime < end;
}

/** Map global timeline seconds → scene + local offset */
export function resolveTime(scenes, globalTime) {
	let offset = 0;
	for (let i = 0; i < scenes.length; i++) {
		const scene = scenes[i];
		const dur = scene.duration || 0;
		if (globalTime < offset + dur || i === scenes.length - 1) {
			return {
				scene,
				sceneIndex: i,
				localTime: Math.max(0, Math.min(globalTime - offset, dur - 0.001)),
				sceneStart: offset,
			};
		}
		offset += dur;
	}
	const last = scenes[scenes.length - 1];
	return {
		scene: last,
		sceneIndex: scenes.length - 1,
		localTime: 0,
		sceneStart: offset - (last?.duration || 0),
	};
}

export function formatTimecode(seconds) {
	const s = Math.max(0, seconds);
	const m = Math.floor(s / 60);
	const sec = Math.floor(s % 60);
	const ms = Math.floor((s % 1) * 10);
	return `${String(m).padStart(2, "0")}:${String(sec).padStart(2, "0")}.${ms}`;
}

export function layerClipLabel(layer) {
	if (layer.type === "text") return layer.data?.content?.slice(0, 24) || "Text";
	if (layer.type === "audio" || layer.type === "video") return layer.data?.label || layer.type;
	if (layer.type === "image") return "Image";
	if (layer.type === "shape") return layer.data?.shape || "Shape";
	if (layer.type === "icon") return layer.data?.icon || "Icon";
	return layer.type;
}

export function normalizeLayer(layer, sceneDuration) {
	const startTime = layer.startTime ?? 0;
	let clipDuration = layer.clipDuration ?? sceneDuration;
	const maxDur = Math.max(MIN_CLIP_DURATION, sceneDuration - startTime);
	clipDuration = Math.min(Math.max(MIN_CLIP_DURATION, clipDuration), maxDur);
	return {
		...layer,
		startTime,
		clipDuration,
		animation: {
			preset: "none",
			duration: 0.6,
			...(layer.animation || {}),
		},
	};
}

export function normalizeProject(project) {
	return {
		...project,
		canvas: {
			width: project.canvas?.width ?? 360,
			height: project.canvas?.height ?? 640,
			presetId: project.canvas?.presetId ?? null,
			background: project.canvas?.background ?? {
				type: "solid",
				fill: "#18181b",
			},
		},
		scenes: (project.scenes || []).map((scene) => {
			const dur = Math.max(MIN_SCENE_DURATION, scene.duration || 5);
			return {
				...scene,
				duration: dur,
				transition: {
					...DEFAULT_SCENE_TRANSITION,
					...(scene.transition || {}),
				},
				enterAnimation: {
					...DEFAULT_SCENE_ENTER_ANIMATION,
					...(scene.enterAnimation || {}),
				},
				layers: (scene.layers || []).map((l) => normalizeLayer(l, dur)),
			};
		}),
	};
}

import { useCallback } from "react";
import { useAppDispatch, useAppSelector } from "@/lib/store/hooks";
import { addLayer } from "@/lib/store/slices/videoEditorSlice";
import { CANVAS_WIDTH, CANVAS_HEIGHT } from "@/lib/video-editor/constants";
import { TEXT_PRESETS } from "@/lib/video-editor/textPresets";
import { SHAPE_PRESETS, ICON_COLOR_PRESETS } from "@/lib/video-editor/shapePresets";
import { DEFAULT_ICON } from "@/lib/video-editor/icons";
import { getMediaDuration, roundMediaDuration } from "@/lib/video-editor/media";

function openFilePicker(accept, onFile) {
	const input = document.createElement("input");
	input.type = "file";
	input.accept = accept;
	input.onchange = (e) => {
		const file = e.target.files?.[0];
		if (file) onFile(file);
	};
	input.click();
}

/** Shared add-layer actions for timeline add strips */
export function useTimelineLayerActions() {
	const dispatch = useAppDispatch();
	const { activeSceneId, project } = useAppSelector((s) => s.videoEditor);
	const canvasW = project.canvas?.width ?? CANVAS_WIDTH;
	const canvasH = project.canvas?.height ?? CANVAS_HEIGHT;

	const add = useCallback(
		(payload, insertAt) => {
			if (!activeSceneId) return;
			dispatch(addLayer({ sceneId: activeSceneId, insertAt, ...payload }));
		},
		[dispatch, activeSceneId],
	);

	const addText = useCallback(
		(insertAt) => {
			const preset = TEXT_PRESETS.find((p) => p.isPlain) ?? TEXT_PRESETS[0];
			add(
				{
					type: "text",
					data: preset.layer,
					overrides: {
						y: CANVAS_HEIGHT / 2 - 50,
						width: CANVAS_WIDTH - 60,
						height: preset.layer.content.includes("\n") ? 100 : 80,
					},
				},
				insertAt,
			);
		},
		[add],
	);

	const addShape = useCallback(
		(insertAt) => {
			const preset = SHAPE_PRESETS[0];
			add(
				{
					type: "shape",
					data: preset.data,
					overrides: {
						x: (CANVAS_WIDTH - preset.size.width) / 2,
						y: (CANVAS_HEIGHT - preset.size.height) / 2,
						width: preset.size.width,
						height: preset.size.height,
					},
				},
				insertAt,
			);
		},
		[add],
	);

	const addIcon = useCallback(
		(insertAt) => {
			add(
				{
					type: "icon",
					data: { icon: DEFAULT_ICON, fill: ICON_COLOR_PRESETS[0], fontSize: 48 },
					overrides: {
						x: CANVAS_WIDTH / 2 - 30,
						y: CANVAS_HEIGHT / 2 - 30,
					},
				},
				insertAt,
			);
		},
		[add],
	);

	const uploadImage = useCallback(
		(insertAt) => {
			openFilePicker("image/*", (file) => {
				const url = URL.createObjectURL(file);
				add({ type: "image", data: { src: url } }, insertAt);
			});
		},
		[add],
	);

	const uploadVideo = useCallback(
		(insertAt) => {
			openFilePicker("video/*", async (file) => {
				const url = URL.createObjectURL(file);
				try {
					const rawDuration = await getMediaDuration(url, "video");
					const mediaDuration = roundMediaDuration(rawDuration);
					add(
						{
							type: "video",
							mediaDuration,
							data: {
								src: url,
								label: file.name,
								mediaDuration,
								muted: false,
								volume: 1,
							},
							overrides: { x: 0, y: 0, width: canvasW, height: canvasH },
						},
						insertAt,
					);
				} catch {
					add(
						{
							type: "video",
							data: { src: url, label: file.name, muted: false, volume: 1 },
							overrides: { x: 0, y: 0, width: canvasW, height: canvasH },
						},
						insertAt,
					);
				}
			});
		},
		[add, canvasW, canvasH],
	);

	const uploadAudio = useCallback(
		(insertAt) => {
			openFilePicker("audio/*", async (file) => {
				const url = URL.createObjectURL(file);
				try {
					const rawDuration = await getMediaDuration(url, "audio");
					const mediaDuration = roundMediaDuration(rawDuration);
					add(
						{
							type: "audio",
							mediaDuration,
							data: { src: url, label: file.name, mediaDuration },
						},
						insertAt,
					);
				} catch {
					add({ type: "audio", data: { src: url, label: file.name } }, insertAt);
				}
			});
		},
		[add],
	);

	return {
		activeSceneId,
		addText,
		addShape,
		addIcon,
		uploadImage,
		uploadVideo,
		uploadAudio,
	};
}

export function uid(prefix = "id") {
	return `${prefix}_${Date.now().toString(36)}_${Math.random().toString(36).slice(2, 8)}`;
}

export function findScene(project, sceneId) {
	return project?.scenes?.find((s) => s.id === sceneId) ?? null;
}

export function findLayer(scene, layerId) {
	return scene?.layers?.find((l) => l.id === layerId) ?? null;
}

export function downloadJson(data, filename = "project.json") {
	const blob = new Blob([JSON.stringify(data, null, 2)], {
		type: "application/json",
	});
	const url = URL.createObjectURL(blob);
	const a = document.createElement("a");
	a.href = url;
	a.download = filename;
	a.click();
	URL.revokeObjectURL(url);
}
